var ST=window.ST||{};ST.show_embed=function(){$embed_field=$('#embed_field');var lang_showcode=$embed_field.data('lang-showcode');$embed_field.hide();$embed_field.after('<a id="show_code" href="#">'+lang_showcode+'</a>');$('#show_code').live('click',function(){$(this).hide();$embed_field.show().select();return false;});};ST.expand=function(){$('.expander').show();$('.expand').click(function(){if($('.paste').hasClass('full')){return false;}
var window_width=$(window).width();var spacer=20;if(window_width<900){window_width=900;spacer=0;}
var new_width=(window_width-(spacer*3));$('.text_formatted').animate({'width':new_width+'px','left':'-'+(((window_width-900)/2-spacer))+'px'},200);return false;});};ST.spamadmin=function(){if($('.content h1').text()=='Spamadmin'){$('.content .hidden').show();$('.content .quick_remove').live('click',function(ev){var ip=$(ev.target).data('ip');if(confirm('Delete all pastes belonging to '+ip+'?')){$.post(base_url+'spamadmin/'+ip,{'confirm_remove':'yes','block_ip':1},function(){window.location.reload();});}
return false;});$(document).tooltip({items:"td.first a",content:function(done){var pid=$(this).attr('href').split('view/')[1];$.get(base_url+'view/raw/'+pid+'?preview',function(data){done(data);});},show:false,hide:false});}
$.fn.addBack=function(selector){return this.add(selector==null?this.prevObject:this.prevObject.filter(selector));}
$('.selectable>tbody').selectable({filter:'tr',cancel:'a',stop:function(){var $deletestack=$(".paste_deletestack");var $input=$("input[name=pastes_to_delete]");$('.inv').show();$deletestack.empty();$input.empty();var res=[];$(".ui-selected").each(function(i,el){var id=$('a',el).attr('href').split('view/')[1];res.push(id);});$deletestack.text(res.join(' '));$input.val(res.join(' '));}});};ST.line_highlighter=function(){var org_href=window.location.href.replace(/(.*?)#(.*)/,'$1');var first_line=false;var second_line=false;$('.text_formatted').on('mousedown',function(ev){if(ev.which==1){window.getSelection().removeAllRanges();}});$('.text_formatted').on('click','li',function(ev){var $this=$(this);var li_num=($this.index()+1);if(ev.shiftKey==1){second_line=li_num;}else{first_line=li_num;second_line=false;}
if(second_line){if(first_line<second_line){sel_start=first_line;sel_end=second_line;}else{sel_start=second_line;sel_end=first_line;}
window.location.href=org_href+'#L'+sel_start+'-L'+sel_end;}else{window.location.href=org_href+'#L'+first_line;}
ST.highlight_lines();});ST.highlight_lines();}
ST.highlight_lines=function(){var wloc=window.location.href;if(wloc.indexOf('#')>-1){$('.text_formatted .container li').css('background','none');var lines=wloc.split('#')[1];if(lines.indexOf('-')>-1){var start_line=parseInt(lines.split('-')[0].replace('L',''),10);var end_line=parseInt(lines.split('-')[1].replace('L',''),10);for(var i=start_line;i<=end_line;i++){$('.text_formatted .container li:nth-child('+i+')').css('background','#F8EEC7');}}else{var re=new RegExp('^L[0-9].*?$');var r=lines.match(re);if(r){var marked_line=lines.replace('L','');$('.text_formatted .container li:nth-child('+marked_line+')').css('background','#F8EEC7');}}}}
ST.crypto=function(){$('button[name=submit]').after('<button id="create_encrypted">Create encrypted</button>');$('#create_encrypted').on('click',function(){var $code=$('#code');var key=ST.crypto_generate_key(32);var plaintext=$code.val();plaintext=LZString.compressToBase64(plaintext);var encrypted=CryptoJS.AES.encrypt(plaintext,key)+'';encrypted=encrypted.replace(/(.{100})/g,"$1\n");$.post(base_url+'post_encrypted',{'name':$('#name').val(),'title':$('#title').val(),'code':encrypted,'lang':$('#lang').val(),'expire':$('#expire').val(),'captcha':$('#captcha').val(),'reply':$('input[name=reply]').val()},function(redirect_url){if(redirect_url.indexOf('E_CAPTCHA')>-1){$('.content .container .message').remove();$('.content .container').prepend('<div class="message error"><div class="container">The captcha is incorrect.</div></div>');}else if(redirect_url.indexOf('invalid')>-1){redirect_url=redirect_url.replace('" /><!-- behind you -->','#'+key+'" />')
$('#create_encrypted').parent().html('<p>'+redirect_url+'</p>');}else{window.location.href=base_url+redirect_url+'#'+key;}});return false;});w_href=window.location.href;if(w_href.indexOf('#')>-1){key=w_href.split('#')[1];var re=new RegExp('^L[0-9].*?$');var r=key.match(re);if(key.indexOf('-')>-1||r){}else{try{var $code=$('#code');var encrypted=$code.val().replace(/\n/g,'');var decrypted=CryptoJS.AES.decrypt(encrypted,key).toString(CryptoJS.enc.Utf8)+'';decrypted=LZString.decompressFromBase64(decrypted);$code.val(decrypted);decrypted=decrypted.replace(/(.{90}.*?) /g,"$1{{{breaking_space}}}");decrypted=decrypted.replace(/&/g,'&amp;').replace(/"/g,'&quot;').replace(/'/g,'&#039;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/ /g,'&nbsp;').replace(/{{{breaking_space}}}/g,' ').replace(/\n/g,'<br />')
$('.text_formatted .container div').html(decrypted);$('.text_formatted').css('background','#efe');$('.replies').hide();for(var i=2;i<=7;i++){$('.meta .detail:nth-child('+i+')').hide();}
$('.meta .spacer:first').hide();$('.qr').hide();}catch(e){}}}}
ST.crypto_generate_key=function(len){var index='abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';var key='';for(var i=0;i<len;i++){key+=index[Math.floor(Math.random()*index.length)]};return key;}
ST.dragdrop=function(){$("#code").fileReaderJS({dragClass:"drag",accept:false,readAsMap:{},readAsDefault:'DataURL',on:{loadend:function(e,file){try{var words=CryptoJS.enc.Base64.parse(e.target.result.split(',')[1]);var utf8=CryptoJS.enc.Utf8.stringify(words);$('#code').val(utf8);}catch(err){console.error(err);console.info('event: ',e);console.info('file: ',file);};}}});}
ST.ace_init=function(){var $code=$('#code');if($code.length<1){return false;}
if(typeof ace=='undefined'){return false;}
$code.after('<div id="editor" style="left: 10px; width: 703px; height: 312px;"></div>');$code.hide();ST.ace_modes=$.parseJSON($('#ace_modes').text());ace.config.set("basePath",base_url+"themes/default/js/ace");ST.ace_editor=ace.edit("editor");ST.ace_editor.setTheme("ace/theme/clouds");ST.ace_editor.getSession().setValue($code.val());ST.ace_editor.getSession().on('change',function(e){$code.val(ST.ace_editor.getValue());});ST.ace_setlang();$('#lang').change(function(){ST.ace_setlang();});}
ST.ace_setlang=function(){var lang=$('#lang').val();var mode='';try{mode=ST.ace_modes[lang];}catch(undefined){mode='text';}
if(mode===undefined){mode='text';}
ST.ace_editor.getSession().setMode("ace/mode/"+mode);}
ST.codemirror_init=function(){if(typeof CodeMirror=='undefined'){return false;}
ST.cm_modes=$.parseJSON($('#codemirror_modes').text());$('#lang').change(function(){ST.codemirror_setlang();});if(typeof ST.cm_editor=='undefined'){ST.cm_editor=CodeMirror.fromTextArea(document.getElementById('code'),{lineNumbers:true,lineWrapping:true,});}
ST.codemirror_setlang();}
ST.codemirror_setlang=function(){var lang=$('#lang').val();var mode=ST.cm_modes[lang];$.get(base_url+'main/get_cm_js/'+lang,function(data){if(data!=''){ST.cm_editor.setOption('mode',mode);}else{ST.cm_editor.setOption('mode',null);}},'script');}
ST.clickable_urls=function(){$('.paste .container').linkify();}
ST.init=function(){ST.expand();ST.show_embed();ST.spamadmin();ST.line_highlighter();ST.crypto();ST.dragdrop();ST.clickable_urls();ST.codemirror_init();ST.ace_init();};$(document).ready(function(){ST.init();});
